features.snippet:
output reg branch;
always @(*) begin
    case (opcode)
        default: branch = 1'bz;
    endcase
end

output reg [1:0] ALUOp;
output reg memWrite;
output reg ALUSrc;
always @(*) begin
    case (opcode)
        default: begin ALUOp = 2'bzz; memWrite = 1'bz; ALUSrc = 1'bz; end
    endcase
end
